        import org.apache.log4j.Logger;
        import sailpoint.object.Identity;
        import sailpoint.server.Auditor;
        import sailpoint.object.AuditEvent;

        String prevgStatus = null;
        String newgStatus = null;
        String prevEmpClass = null;
        String newEmpClass = null;
        String strEmail = null;
        String prevType = null;
        String newType = null;

        try{

        if(event != null){
        oldIdentity = event.getOldObject();
        newIdentity = event.getNewObject();    
        if(oldIdentity!=null && newIdentity!=null){
        prevEmpClass = oldIdentity.getStringAttribute("employeeClass");
        newEmpClass = newIdentity.getStringAttribute("employeeClass");
        prevgStatus = oldIdentity.getStringAttribute("gsuiteStatus");
        newgStatus = newIdentity.getStringAttribute("gsuiteStatus");
        prevType = oldIdentity.getType();
        newType = newIdentity.getType();
        }
        } else if(null != inputMap){
        prevEmpClass = inputMap.get("old_employee_class");  
        newEmpClass = inputMap.get("new_employee_class");
        prevgStatus = inputMap.get("old_gsuite_status");
        newgStatus = inputMap.get("new_gsuite_status");
        }

        Identity identity = context.getObject(Identity.class, identityName);
        if(identity!= null){
        modifyGsuiteLicense(identityName,"empClassChange");

        strEmail=identity.getAttribute("email");

        //added a check if new type is contractor and old type is employee, only in that case set the ctrexpDt to empty
        if(prevType!=null && newType!=null && !(prevType.equalsIgnoreCase(newType)) && (newType.equalsIgnoreCase("contractor") && (prevType.equalsIgnoreCase("employee") )) ){
            boolean isInPersonaEnabledMinistry = isInMinistriesList(identityName);
            if(!isInPersonaEnabledMinistry){
        	boolean isPopulated = isAssignEndDatePopulated(identity);
                if(!isPopulated){
                    //set Contractor Expiration Date if identity is a Non-Persona Contractor
                    String expDate = calculateContractorExpirationDate(identity);

                    if(Util.isNotNullOrEmpty(expDate)){
                    identity.setAttribute("ctrexpDt", expDate);
                    }
                }else{
                    identity.setAttribute("ctrexpDt", " ");
                }
            }else{
          	    boolean isPopulated = isAssignEndDatePopulated(identity);
          	    if(isPopulated){
            	    identity.setAttribute("ctrexpDt", " ");
          	    }
      		}
        }

        context.saveObject(identity);

        //Write Audit records to IIQ.
        String auditString1 = "Identity that was processed-EmpClass Change: "+identityName;
        String auditString2 = "Previous EmpClass Value : "+prevEmpClass +", New EmpClass value : "+newEmpClass;
        String auditString3 = "Previous GSuite Status : "+prevgStatus +", New Gsuite Status : "+newgStatus;


        String strTarget=identityName;
        String strAction = "EmployeeClassChange";
        if(Auditor.isEnabled(strAction)){
        AuditEvent adtEvent = new AuditEvent();
        adtEvent.setTarget(strTarget);
        adtEvent.setAction(strAction);
        adtEvent.setAccountName(strEmail);
        adtEvent.setAttributeName("EmployeeClassChange Process");
        adtEvent.setApplication("IIQ");

        adtEvent.setString1(auditString1);
        adtEvent.setString2(auditString2);
        adtEvent.setString3(auditString3);

        Auditor.log(adtEvent);
        context.commitTransaction();
        }
        }
        }catch(Exception e){
        throw e;
        }
